using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Constructor_SetsPageIndex()
    {
        // Arrange & Act
        var list = new PaginatedList<int>(new List<int> { 1, 2 }, 10, 3, 5);

        // Assert
        Assert.AreEqual(3, list.PageIndex);
    }

    [TestMethod]
    [DataRow(10, 5, 2, DisplayName = "10 items / 5 per page = 2 pages")]
    [DataRow(10, 3, 4, DisplayName = "10 items / 3 per page = 4 pages (ceiling)")]
    [DataRow(1, 10, 1, DisplayName = "1 item / 10 per page = 1 page")]
    [DataRow(0, 5, 0, DisplayName = "0 items / 5 per page = 0 pages")]
    [DataRow(11, 5, 3, DisplayName = "11 items / 5 per page = 3 pages")]
    public void Constructor_CalculatesTotalPagesCorrectly(int count, int pageSize, int expectedTotalPages)
    {
        // Act
        var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

        // Assert
        Assert.AreEqual(expectedTotalPages, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_AddsAllItemsToList()
    {
        // Arrange
        var items = new List<string> { "alpha", "beta", "gamma" };

        // Act
        var list = new PaginatedList<string>(items, 3, 1, 3);

        // Assert
        Assert.AreEqual(3, list.Count);
        Assert.AreEqual("alpha", list[0]);
        Assert.AreEqual("beta", list[1]);
        Assert.AreEqual("gamma", list[2]);
    }

    [TestMethod]
    [DataRow(1, false, DisplayName = "First page has no previous")]
    [DataRow(2, true, DisplayName = "Second page has previous")]
    [DataRow(5, true, DisplayName = "Fifth page has previous")]
    public void HasPreviousPage_ReturnsCorrectValue(int pageIndex, bool expected)
    {
        // Act
        var list = new PaginatedList<int>(new List<int>(), 50, pageIndex, 10);

        // Assert
        Assert.AreEqual(expected, list.HasPreviousPage);
    }

    [TestMethod]
    [DataRow(1, 20, 5, true, DisplayName = "First of 4 pages has next")]
    [DataRow(4, 20, 5, false, DisplayName = "Last page has no next")]
    [DataRow(1, 5, 5, false, DisplayName = "Single page has no next")]
    [DataRow(3, 20, 5, true, DisplayName = "Middle page has next")]
    public void HasNextPage_ReturnsCorrectValue(int pageIndex, int count, int pageSize, bool expected)
    {
        // Act
        var list = new PaginatedList<int>(new List<int>(), count, pageIndex, pageSize);

        // Assert
        Assert.AreEqual(expected, list.HasNextPage);
    }

    [TestMethod]
    public void Create_FirstPage_ReturnsCorrectItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 15).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 5);

        // Assert
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(5, result[4]);
    }

    [TestMethod]
    public void Create_MiddlePage_ReturnsCorrectItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 5);

        // Assert
        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages);
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(6, result[0]);
        Assert.AreEqual(10, result[4]);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 12).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 3, 5);

        // Assert
        Assert.AreEqual(3, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        Assert.AreEqual(2, result.Count);
        Assert.AreEqual(11, result[0]);
        Assert.AreEqual(12, result[1]);
    }
}

