using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using System;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _sut;

    [TestInitialize]
    public void Setup()
    {
        _sut = new NotificationService();
        // Drain the static queue to ensure isolation
        while (_sut.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut?.Dispose();
        // Drain the queue again after each test
        using var drainer = new NotificationService();
        while (drainer.ReceiveNotification() != null) { }
    }

    [TestMethod]
    public void SendNotification_EnqueuesNotification_CanBeReceived()
    {
        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE, "admin");
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Student", result.EntityType);
        Assert.AreEqual("1", result.EntityId);
        Assert.AreEqual("CREATE", result.Operation);
        Assert.AreEqual("admin", result.CreatedBy);
        Assert.IsFalse(result.IsRead);
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_GeneratesDisplayNameMessage()
    {
        // Act
        _sut.SendNotification("Course", "101", "Chemistry", EntityOperation.CREATE, "admin");
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("New Course 'Chemistry' has been created", result.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_GeneratesIdBasedMessage()
    {
        // Act
        _sut.SendNotification("Course", "101", EntityOperation.CREATE, "admin");
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("New Course (ID: 101) has been created", result.Message);
    }

    [TestMethod]
    public void SendNotification_CreateOperation_GeneratesCorrectMessage()
    {
        // Act
        _sut.SendNotification("Student", "5", "John Smith", EntityOperation.CREATE);
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.AreEqual("New Student 'John Smith' has been created", result.Message);
    }

    [TestMethod]
    public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
    {
        // Act
        _sut.SendNotification("Student", "5", "John Smith", EntityOperation.UPDATE);
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.AreEqual("Student 'John Smith' has been updated", result.Message);
    }

    [TestMethod]
    public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
    {
        // Act
        _sut.SendNotification("Student", "5", "John Smith", EntityOperation.DELETE);
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.AreEqual("Student 'John Smith' has been deleted", result.Message);
    }

    [TestMethod]
    public void ReceiveNotification_WhenEmpty_ReturnsNull()
    {
        // Act
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_ReturnsFIFOOrder()
    {
        // Arrange
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);
        _sut.SendNotification("Course", "2", EntityOperation.UPDATE);
        _sut.SendNotification("Department", "3", EntityOperation.DELETE);

        // Act & Assert
        var first = _sut.ReceiveNotification();
        Assert.AreEqual("Student", first.EntityType);
        Assert.AreEqual("1", first.EntityId);

        var second = _sut.ReceiveNotification();
        Assert.AreEqual("Course", second.EntityType);
        Assert.AreEqual("2", second.EntityId);

        var third = _sut.ReceiveNotification();
        Assert.AreEqual("Department", third.EntityType);
        Assert.AreEqual("3", third.EntityId);
    }

    [TestMethod]
    public void SendNotification_DefaultUserName_IsSystem()
    {
        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.AreEqual("System", result.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAt()
    {
        // Arrange
        var before = DateTime.Now;

        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);
        var result = _sut.ReceiveNotification();
        var after = DateTime.Now;

        // Assert
        Assert.IsTrue(result.CreatedAt >= before && result.CreatedAt <= after);
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act & Assert - MarkAsRead is a no-op but should not throw
        _sut.MarkAsRead(1);
        _sut.MarkAsRead(999);
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        // Act & Assert
        var service = new NotificationService();
        service.Dispose();
        // Should not throw
    }

    [TestMethod]
    public void SendNotification_WithNullDisplayName_FallsBackToId()
    {
        // Act
        _sut.SendNotification("Student", "42", null, EntityOperation.UPDATE);
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.AreEqual("Student (ID: 42) has been updated", result.Message);
    }

    [TestMethod]
    public void SendNotification_WithEmptyDisplayName_FallsBackToId()
    {
        // Act
        _sut.SendNotification("Student", "42", "  ", EntityOperation.DELETE);
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.AreEqual("Student (ID: 42) has been deleted", result.Message);
    }

    [TestMethod]
    public void SendNotification_MultipleNotifications_AllQueued()
    {
        // Arrange & Act
        for (int i = 0; i < 5; i++)
        {
            _sut.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
        }

        // Assert
        for (int i = 0; i < 5; i++)
        {
            var n = _sut.ReceiveNotification();
            Assert.IsNotNull(n);
            Assert.AreEqual(i.ToString(), n.EntityId);
        }
        Assert.IsNull(_sut.ReceiveNotification());
    }
}

